var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그런 일이 있었군요.","JPN":"そんなことがあったんですね。","ENG":"So, that's what happened.","TWN":"原來是這樣。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그럼 그 때 폭발이 일어난 가게에 계셨던 사장님은 괜찮으신 건가요?","JPN":"では、あの時爆発が起きた店にいらっしゃったオーナーは大丈夫ですか？","ENG":"Then, what about your boss, who was in the bar at the time of the explosion? Is she okay?","TWN":"那爆炸當時在店裡的老闆娘沒事嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"으음… 니콜 양… 한잔 더~","JPN":"ううん……ニコルちゃん……おかわり……","ENG":"Mm... Nicole... Gimme one more glass...","TWN":"嗯…妮可…再來一杯～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"보다시피 멀쩡하세요. 운이 좋으셨대요.","JPN":"ご覧の通り元気です。運が良かったそうです。","ENG":"As you can see, yes. She was lucky.","TWN":"就像你看到的，老闆娘非常平安，消防員都說她很幸運。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"다행이네요. 범죄조직의 폭탄테러라니… 상상만 해도 끔찍해요.","JPN":"よかったですね。犯罪組織の爆弾テロだなんて……\\n想像しただけでもゾッとします。","ENG":"I'm glad. Bombing by a criminal organization... *Shudder* So terrible!","TWN":"真的欸～犯罪組織的炸彈恐怖事件…光想就覺得可怕。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그나마 다행인 건, 덕분에 그라운드 원으로 와서 가게를 새로 차렸다는 거죠.","JPN":"不幸中の幸いなのは、おかげでグラウンド・ワンに来て新しい店をオープンできたことです。","ENG":"But because of it, we moved to Ground One and opened this new bar.","TWN":"不過也因為這樣，店才能搬到G1重新開張。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이전 동네는 범죄자들 놀이터라고 해도 과언이 아니었거든요.","JPN":"以前の町は犯罪者のたまり場と言っても過言ではない場所でしたので。","ENG":"The previous neighborhood we were in was practically a playground for criminals.","TWN":"之前那個地方，說是犯罪者的天堂根本也不為過。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그 점에 대해선 걱정 마세요.","JPN":"その点については心配いりません。","ENG":"You don't have to worry about that here.","TWN":"這點你大可以放心！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"여기 그라운드 원은 대균열의 근원지라는 이유로 아직 위험하단 인식이 남아 있지만…….","JPN":"ここグラウンド・ワンは大亀裂の根源地という理由で\\nまだ危険だという認識が残っていますが……","ENG":"People think Ground One is dangerous because it's built on a Grand Dimension Crevice,","TWN":"Ｇ1這裡雖然是大峽谷的發生地點，所以大家對這裡的印象還是覺得有點危險……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"태스크포스도 많이 모여 있고, 관리국 직할 도시인 만큼 치안 유지는 확실하니까요.","JPN":"タスクフォースカンパニーもたくさん集まっていますし、\\n管理局直轄都市だけに治安維持はしっかりしてますからね。","ENG":"but a lot of TASKFORCE companies are based here, not to mention it's an Administration Direct Control City, which means it's safe.","TWN":"不過這裡有聚集許多的特遣勢力，而且又是管理局直轄市，治安還算是滿好的！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"정말 그런 것 같아요.","JPN":"本当にそうだと思います。","ENG":"I think you're right.","TWN":"好像是欸！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"여기서 지내는 동안 누가 칼로 협박을 당하거나 납치되는 일은 아직 한 번도 없었거든요.","JPN":"ここで暮らし始めてから、誰かがナイフで脅されたり攫われたりすることが\\nまだ一度もありませんし。","ENG":"Since I came here, I've never seen anyone being mugged at knifepoint or kidnapped.","TWN":"我們搬來這裡後，都還沒發生過有人亮刀威脅，或是綁架擄人的事。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네? 납치요?","JPN":"はい？　攫われる？","ENG":"Huh? Kidnapped?","TWN":"你說什麼？綁架擄人？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"니콜~ 스무디 줘~","JPN":"ニコル、スムージーちょ～だい～","ENG":"Nicole, I want smoothie.","TWN":"妮可～我要喝果汁～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"일어났어요? 손님이 계시니까 조금만 기다려요.","JPN":"起きましたか？　お客様がいらっしゃるので少しだけ待ってくださいね。","ENG":"Are you awake? I've got a customer. You just wait.","TWN":"你起來啦？現在有客人在，你先等一下。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"응…?","JPN":"うむ……？","ENG":"Mm?","TWN":"嗯…？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"오오, 새로운 손님이로구나!","JPN":"おお、新しいお客さんだな！","ENG":"Ooo, a new customer!","TWN":"哇喔～有新的客人！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"어머, 귀여운 꼬마네요. 사장님 친척분인가 봐요.","JPN":"あら、可愛らしいおチビちゃんですね。社長の親戚の方ですか？","ENG":"Oh, who's this cute little girl? Is she your boss's relative?","TWN":"哇～好可愛的小朋友，是老闆娘的親戚嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"꼬마가 아냐! 이 몸은 마왕 모르가나 모드렛이니라!","JPN":"チビではない！　吾輩は魔王、モルガナ・モードレッドである！","ENG":"I'm not a girl. I'm Morgana Mordred, the Demon Lord!","TWN":"什麼小朋友！本王是魔王 莫甘娜 莫德雷！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그러니 손님답게 어서 이 몸에게 맛있는 공물을 바치도록!","JPN":"だからお客さんらしく早く吾輩においしい供物を捧げたまえ！","ENG":"So, be a good customer and offer me some delicious offerings!","TWN":"身為客人，還不趕快獻上好吃的給本王！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"맛있는…… 공물?","JPN":"おいしい……供物？","ENG":"Delicious... offerings?","TWN":"獻上……好吃的？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아, 바나나 우유라면 있는데. 이거 줄까?","JPN":"あ、バナナジュースならあるけど、飲む？","ENG":"Ah, I've got some banana milk. Want it?","TWN":"喔！我有巧克力牛奶，你要嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"바나나 우유?","JPN":"バナナジュース？","ENG":"Banana milk?","TWN":"巧克力牛奶？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"…오오! 우오오오! 뭐냐! 이 엄청난 맛은!","JPN":"……おお！　うおおお！　なんだ、この凄まじい味は！","ENG":"Whoa! Whoaaah! What is this? It's so delicious!","TWN":"…哇喔！哇喔喔喔！這是什麼！怎麼會這麼好喝！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"바나나는 아니지만 바나나보다 더 맛있도다!","JPN":"バナナではないが、バナナよりおいしいぞ！","ENG":"It doesn't really taste like banana, but it's even more delicious!","TWN":"不是巧克力卻比巧克力更美味！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"처음 먹어 보는구나. 좋아해서 다행이다.","JPN":"はじめて飲んだのね。喜んでくれてよかった。","ENG":"So, you've never had it before, have you? I'm glad you like it.","TWN":"你是第一次喝到嗎？喜歡就好～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"좋다, 인간! 너도 특별히 이 몸의 하수인으로 삼아 주마!","JPN":"よし、人間！　お前も特別に吾輩の下僕にしてやる！","ENG":"Alright, human. I hereby accept you as my special subject.","TWN":"很好！本王就特別收你為手下吧！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"매일 이곳에 와서 바나나 우유를 바치도록 하라!","JPN":"毎日ここに来てバナナジュースを捧げるがよい！","ENG":"Now, you may come here every day with this banana milk for me.","TWN":"你每天都要來向本王獻上巧克力牛奶！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그럴까? 분위기도 마음에 들고 우리 회사랑 이웃이기도 하니까…….","JPN":"そうしようかな？　雰囲気も気に入ったし、うちの会社とお隣さん同士だし……","ENG":"Sure. I like your bar's atmosphere, and it's right next to my company, too.","TWN":"是喔？這邊的氣氛是滿好的，又在我們公司隔壁而已……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"음… 하지만 술은 줄이기로 결심했는데…….","JPN":"うーん……でもお酒は控えると決心したのに……","ENG":"Mm... But I promised myself to cut down on drinking...","TWN":"可是…我才想說要少喝點酒……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"손님~ 여기 저희 바의 인기 칵테일, 벨벳 블로섬입니다.","JPN":"お待たせしました。こちらのバーの人気カクテル、ベルベットブロッサムです。","ENG":"Here's one of our favorite cocktails, the Velvet Blossom.","TWN":"小姐～這是我們店的招牌 紅絲絨花雞尾酒。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앞으로도 자주 뵐 것 같으니, 첫 잔은 서비스로 드릴게요!","JPN":"これからもよくお会いすると思いますので、一杯目はサービスしますね！","ENG":"Since I have a feeling that you'll be here often, your first drink is on us.","TWN":"第一杯由本店招待！希望以後常來喔～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"와아, 예쁜 칵테일이네요! 고맙습니다!","JPN":"わあ、きれいなカクテルですね！　ありがとうございます！","ENG":"Ooo, it looks so pretty! Thank you!","TWN":"哇～好美的雞尾酒！謝謝！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_SHAKING_COCK"},{"id":"L39_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그럼 딱 한 잔만…","JPN":"では、一杯だけ……","ENG":"Then, I'll have just this one.","TWN":"就一杯…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그러니까아… 내가 왜 남자들한테 인기가 없다는 건데에에~","JPN":"だからぁ……私はどうして男からモテないのよぉ～","ENG":"Sooo... why don't men like meee?","TWN":"你說說看…為什麼我不是男生的菜～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L44_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"나처럼 조신하고 착한 여자가 어딨다고… 우이씨…","JPN":"私みたいな慎ましくて優しい女なんてどこにもいないよぉ？　んもー……","ENG":"I'm a good, kind womaaaan... Sheeeshhh...","TWN":"像我這麼好的女生上哪找…可惡…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(우와, 금방 취하셨네요. 성격이 점점 바뀌고 있는 것 같은데…)","JPN":"(うわあ、すぐ酔ってしまいましたね。性格がだんだん変わってきてますが……)","ENG":"(Whoa, she got drunk really quickly! And now, her personality is changing...)","TWN":"(哇，這麼快就醉啦？酒品好像不太好欸…)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(좋아! 이럴 때일수록 당황하지 말고! 배운 대로 손님의 기분에 공감해드리자고요!)","JPN":"(よし！　こういう時こそ慌てず！\\n教わったとおりにお客様の気分に共感しましょう！)","ENG":"(Alright! Stay calm, Nicole! You know what to do to build rapport with your customers!)","TWN":"(不怕！這種時候千萬不能慌！就照之前學的，要附和對方！)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그러게요. 정말 이상하네요. 하나 씨 같은 미인이 매번 퇴짜를 맞다니.","JPN":"そうですね。本当におかしいですね。\\nスズカさんのような美人が毎回振られるなんて。","ENG":"That's right. That really doesn't make sense. Why would such a beautiful woman like you get dumped after just one date?","TWN":"對啊，超奇怪的，像你這麼好的女生，怎麼都沒男生看上你呢？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그렇게 소개팅을 많이 했는데 제대로 된 남자 하나 못 만난다는 게 말이나 되는 소린가요?","JPN":"そんなに合コンをたくさんしたのに、\\nまともな男に出会えないなんてあんまりですよ！","ENG":"You've been on so many blind dates, and yet you haven't met anyone you like. That's not right, is it?","TWN":"參加過這麼多場的聯誼，竟然都沒有成功交往過，這合理嗎？！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"으하아앙…! 너무해! 너무하다고!","JPN":"ううううう……！　ひどい！　ひどいわ！","ENG":"Boohoo! Cruel! So cruel!","TWN":"嗚啊嗚啊…！真的！好過分！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"맞아요! 정말 너무하죠!","JPN":"ですです！　ひどい話です！","ENG":"I know! It's so cruel!","TWN":"對啊！超過分的！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"지금껏 얼마나 많이 노력해 왔는데! 하나 씨에게 맞는 짝이 한 명도 없다니! 세상은 부조리함으로 가득한 게 틀림없어요!","JPN":"今までどれだけ努力してきたか！　スズカさんに相応しい相手が一人もいないなんて！\\nこの世界は不条理に満ちているに違いありません！","ENG":"You've been trying so hard to find the man of your dreams, in vain! This world is full of injustice and unfairness!","TWN":"你這麼努力認真！怎麼會都遇不到對的人呢？這世界真的是太不公平！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"크흡…! 으하하아앙!","JPN":"ぐふっ……！　ふええええん！","ENG":"*Sniffle...* Boohoo!","TWN":"嗚嗚…！嗚啊嗚啊！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(어라? 왜 점점 악화되는 거 같죠? 이럴 땐 같이 울어드려야 하나?)","JPN":"(あれ？　どうして悪化し続けるのでしょう？\\nこういう時は一緒に泣いたほうがいいのでしょうか？)","ENG":"(Err, why is she getting worse? Should I... cry with her?)","TWN":"(哇咧？怎麼好像反而哭得更慘？這種時候是要陪她一起哭嗎？)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"니콜 양, 여기서부터는 내가 맡을게.","JPN":"ニコルちゃん、ここからはアタシが代わるわ。","ENG":"Nicole, I'll take things from here.","TWN":"妮可，接下來就交給我吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? 그런… 혹시 제가 무슨 실수를 한 건가요?","JPN":"はい？　そんな……もしかして私が何かやらかしましたか？","ENG":"Sorry? Erm, did I do something wrong?","TWN":"嗯？請問…我有哪裡做錯嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"실수는 아니야.","JPN":"やらかしてはないわ。","ENG":"Not exactly.","TWN":"你沒有做錯。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"하지만 취한 사람에겐 단순한 공감보다 더 직설적인 화법이 필요할 때도 있거든.","JPN":"でも、酔った人には単純な共感より、もっとストレートな話術が必要な時もあるの。","ENG":"But sometimes straightforwardness works better than empathy where drunk people are concerned.","TWN":"只是對於喝醉的人來說，比起單純地附和，有時候也需要更直接的表達。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그, 그렇군요.","JPN":"そ、そうですか……","ENG":"I-I see.","TWN":"這樣喔！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그럼 부탁드리겠습니다.","JPN":"では、お願いします。","ENG":"Okay, then I'll leave her to you.","TWN":"那就麻煩你囉。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(휴, 다행이네요.)","JPN":"(ふう、よかったです。)","ENG":"(Whew, what a relief!)","TWN":"(呼，太好了！)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(지금까지 그레모리 씨에게 상담받은 분들은 전부 만족하며 돌아가셨으니까요.)","JPN":"(今までグレモリーさんに相談された方は、\\nみんな満足してお帰りになりましたからね。)","ENG":"(So far, everyone who talked to Gremory went home happily.)","TWN":"(目前葛茉莉接待過的客人，每一個都是心滿意足地離開的。)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"하나 양? 혹시 자기가 남자를 보는 눈이 너무 높다고 생각한 적은 없어?","JPN":"スズカちゃんは、自分が男を見る目が高すぎると思ったことはない？","ENG":"Hana, don't you ever think that your standards for men are too high?","TWN":"荷娜？你有沒有想過，或許是你挑男人的眼光太高？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"헉?!","JPN":"えっ！？","ENG":"*Gasp!*","TWN":"哇賽？！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"…네?","JPN":"……はい？","ENG":"Excuse me?","TWN":"…什麼？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"흑… 제가 너무 많은 걸 바라는 걸까요? 우리 회사 사람들 정도만 돼도 좋은데…","JPN":"ぐすん……私があまりにもハードルを高くしているんですかね？\\nうちの会社の人程度でいいのに……","ENG":"*Sniffle...* You think I expect too much from them? But I just want someone who's as good as my coworkers...","TWN":"嗚…是我要求太多嗎？只要有我們公司員工的水準就可以啦…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그래? 하나 양의 회사에 있는 사람들은 어떤데? 한 사람만 떠올려 볼래?","JPN":"そう？　スズカちゃんの会社にいる人たちはどうなの？\\n一人だけ思い浮かべてみて？","ENG":"Do you? Okay, then how are your coworkers? Can you give me an example?","TWN":"是嗎？你公司的人如何？可以舉個例來聽聽嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아…","JPN":"あ……","ENG":"Ah...","TWN":"嗯…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"얼마 전에 입사한 신입 카운터분이요.","JPN":"この前入社した新入カウンターです。","ENG":"There's this Counter who recently joined my company.","TWN":"之前有一個新來的制裁者。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"처음엔 회사에 적응을 잘 못 하고 싸움만 잘하는 고독한 늑대 느낌이었는데…","JPN":"最初は会社に馴染めず、\\n強いけど喧嘩ばかりする孤独な狼みたいな感じだったのに……","ENG":"At first, this rookie was like a lone wolf who was good at fighting, but unable to mesh with the others.","TWN":"雖然她的能力很好，但她一開始不適應職場生活，感覺就像孤獨的一匹狼…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"요즘은 자주 업무에 도움을 받기도 하고, 사람들과도 친하게 지내려는 모습이 뭔가…","JPN":"最近はよく仕事を手伝ってもらったり、\\n他の人とも仲良くしようとする姿がなんだか……","ENG":"But recently, this rookie has been asking others for help and trying really hard to get along with them.","TWN":"但她最近開始會幫忙工作上的事，也很努力地想和大家相處…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"덩치만 큰 순한 강아지 같달까.","JPN":"体だけ大きくて、性格は穏やかな子犬みたいというか。","ENG":"That reminds me of a big, gentle dog.","TWN":"感覺就像一隻塊頭很大卻很溫馴的狗狗？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"알지, 알지. 원래는 차가운 줄만 알았던 남자가 보여주는 따뜻한 반전 매력! 게다가 실력까지 갖춘 카운터라면 반할 만 하지.","JPN":"わかるわ。最初は冷たいと思っていた男が見せてくれた温かい面で\\n気づく意外な魅力！　しかも実力まで備えたカウンターなら惚れてもおかしくないわ。","ENG":"Ooo, I know what you mean. You want someone who looks cold on the outside, but has a heart of gold. If he's also a skilled Counter, phew! I'm in!","TWN":"我懂我懂，原本以為他很冷漠，但其實個性溫暖，那種反差的魅力！而且又是很有能力的制裁者，怎麼可能不喜歡他！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"신입이라면 불러내는 것도 어렵지 않겠다. 이참에 확 고백해 버리는 건 어때?","JPN":"新人なら呼び出すのも難しくないんじゃない。\\nこれを機に思い切って告白しちゃうのはどう？","ENG":"If he's new to your company, he'd want to do anything to impress you, too. Why don't you call him and have him come here?","TWN":"既然是新來的，那應該很好使喚吧？要趁這個機會找他出來，跟他告白嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"안 돼요. 여자예요.","JPN":"いけません。相手は女性です。","ENG":"No. It's a woman.","TWN":"那怎麼可以！她是女生欸！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그게 중요한 부분?","JPN":"それって問題になるの？","ENG":"Does that matter?","TWN":"這很重要嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"저한테는 중요하다고요!","JPN":"私にとっては問題になります！","ENG":"Yes, it does to me!","TWN":"對我來說很重要！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"흐음.","JPN":"ふうん。","ENG":"Hmm...","TWN":"呵呵～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그럼 다른 사람은 어때? <color=#ffd34c>회사 사람들</color>이라며?","JPN":"じゃあ、他の人はどう？　<color=#ffd34c>会社の人</color>程度でいいのよね？","ENG":"Then, who else? You said <color=#ffd34c>coworkers</color>.","TWN":"那其他人呢？公司應該還有<color=#ffd34c>其他人</color>吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"으음… 저희 부사장님은 항상 냉철하고 자기 일에 열정적이세요.","JPN":"えっと……副社長は常に落ち着いていて、自分の仕事に情熱的です。","ENG":"Mm... My vice president is extremely rational and passionate about work.","TWN":"嗯…副總個性非常冷靜，只熱衷於自己的事。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"강하고 책임감이 넘치시는 분이라 아직도 혼자 지내신다는 게 이해가 안 될 정도로요.","JPN":"強くて責任感が溢れる方なので、まだ独身というのが理解できないくらいです。","ENG":"I don't understand why such a strong, responsible person is still single.","TWN":"她也是能力很好，而且非常有責任感，我也覺得很奇怪，為什麼她到現在都是孤家寡人？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"아아, 좋지~ 한 회사의 부사장이 쿨한 능력남이라면 안 끌리는 게 이상하지.","JPN":"ああ、いいわね～。一企業の副社長がクールで仕事もできちゃうなら惹かれて当然だわ。","ENG":"Ah, sure. It'd be strange if you weren't attracted to someone so powerful and confident.","TWN":"哇喔～很棒～身為一家公司的副總，想必是位高富帥吧！怎麼可能不愛上他！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그 정도면 어느 정도 나이 차는 극복할 수 있겠는데? 한 번쯤 덤벼볼 만하지 않아?","JPN":"その感じなら、ある程度の年の差は克服できそうだけど？\\n一度くらい狙ってみるべきじゃない？","ENG":"I don't know how old he is, but it doesn't seem like age difference matters. Why don't you feel him out?","TWN":"俗話說年齡不是距離，要勇敢愛一次嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그, 그렇게 나이차가 나진 않아요! 하지만 역시 성별에 문제가 있어서…!","JPN":"そ、そこまで年の差はありません！　でもやっぱり性別の壁があって……！","ENG":"N-not that much older than me, but again, she's a woman...","TWN":"呃…我們年紀是沒有差很多啦！只是一樣有性別的問題…！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"아쉽네. 하지만 내가 남의 취향을 강요할 순 없으니까.","JPN":"それは残念ね。でもアタシが人の好みを強要することはできないから。","ENG":"What a shame! But I get that isn't your thing.","TWN":"真可惜～不過我也無法強迫你改變想法。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그럼 여자가 아닌 이상형은 회사에 없는 거야?","JPN":"じゃあ、女性じゃない理想の人は会社にいないの？","ENG":"Isn't there anyone in your company that's not female?","TWN":"所以你公司裡都沒有非女性的理想對象嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아…","JPN":"あ……","ENG":"Ah...","TWN":"嗯…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"저희 사장님이요.","JPN":"うちの社長です。","ENG":"My boss.","TWN":"就我們老闆吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"사장님은 저를 포함해서 모든 사원분들에게 무척 친절한 분이세요.","JPN":"社長は私を含めて、すべての社員にとても親切な方です。","ENG":"He's kind to everyone in the company, including me.","TWN":"老闆對每位員工都非常地親切。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"가끔 자기를 본 딴 동상에 집착하는 엉뚱한 면을 보이긴 하지만, 그런 면이 오히려 귀엽달까… ","JPN":"たまにご自身がモデルの銅像に執着する突拍子もない面も見せるけど、\\nそういうところがむしろ可愛いというか……","ENG":"Sometimes, he's a bit eccentric of being obsessed with his statues that look like himself, but I find that's cute...  ","TWN":"雖然有時候對他的等身銅像，有莫名的堅持，不過這樣好像也滿可愛的… "},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그런 대하기 편한 성격 덕분에 사원들이 따르는 것 같기도 하구우…","JPN":"そんな接しやすい性格のおかげで社員たちが慕っているような気もするしぃ……","ENG":"Also, he's not authoritative, which makes him popular among his employees...","TWN":"因為他不會讓人有距離感，所以員工們也都很願意替他效勞…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"으으… 제가 취하긴 한 모양이네요. 이런 얘긴 아무한테도 한 적이 없는데…","JPN":"むう……だいぶ酔ってきたようです。こんな話は誰にもしたことがないのに……","ENG":"Aww, I really must be drunk. I've never told anyone this before...","TWN":"呃…我好像喝醉了，這些話我從來沒對其他人說過…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그 사장님을 나에게 빼앗긴다면 어떤 기분일 것 같아?","JPN":"その社長をアタシに奪われたらどんな気分になると思う？","ENG":"How would you feel if I stole him from you?","TWN":"我把老闆搶過來的話，你會作何感想？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"어떻게 그런 짓을…!","JPN":"どうしてそんなことを……！","ENG":"No, you can't!","TWN":"你怎麼可以…！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"…이 아니라…!","JPN":"……じゃなくて！","ENG":"No, I mean...","TWN":"…不是啦…！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"사장님은 여자는 아니지만 로봇이시거든요.","JPN":"社長は女性ではないけど、ロボットなんです。","ENG":"The Boss is not a woman, but he's a robot.","TWN":"我的意思是，雖然老闆不是女生，但他是機器人！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"생리적인 거부감을 떠나 애초에 사람이 아니라 그런 말씀하셔도 소용없어요.","JPN":"生理的な抵抗感はさておき、そもそも人間ではないので、そんなことを言っても無駄ですよ。","ENG":"I'm not interested in women, but I'm not interested in robots, either.","TWN":"排除生理方面的問題，他本來就不算是人類，所以不在討論範圍內啦～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"로봇?","JPN":"ロボット？","ENG":"A robot?","TWN":"機器人？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"하지만 하나 씨 눈동자에 비치는 사장님은 로봇이 아닌 것 같은데?","JPN":"でもスズカちゃんの瞳に映る社長はロボットじゃないみたいだけど？","ENG":"But I don't think the image reflected in your eyes is that of a robot.","TWN":"可是荷娜，你的眼睛背叛了你的心，我在你眼裡看到的老闆不是機器人啊？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"…네?","JPN":"……はい？","ENG":"Huh?","TWN":"…什麼？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"제… 눈동자요?","JPN":"私の……瞳ですか？","ENG":"My eyes?","TWN":"我的…眼裡？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"하나 양도 알고 있잖아. 그 사장님, 로봇이 아니라는 거.","JPN":"スズカちゃんだって知っているでしょ。あの社長が、ロボットじゃないことは。","ENG":"Hana, you know he's not a robot.","TWN":"你也很清楚吧？你的老闆並不是機器人。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"푸훗!","JPN":"ぷっ！","ENG":"Poof!","TWN":"噗哈哈！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"왜 갑자기 눈을 질끈 감고 그래?","JPN":"なんで急に目を閉じたの？","ENG":"Why did you close your eyes all of a sudden?","TWN":"幹嘛突然把眼睛閉起來？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"정말로 내가 하나 씨 눈동자에서 뭘 봤다고 생각한 거야?","JPN":"本当にアタシがスズカちゃんの瞳から何か見たとでも思ったの？","ENG":"Did you really think I saw something through your eyes?","TWN":"你真的以為我能從你的眼睛裡看到東西嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"하… 하지만…","JPN":"で、でも……","ENG":"B-but...","TWN":"可…可是…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"하나 양.","JPN":"スズカちゃん。","ENG":"Hana.","TWN":"荷娜。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"로봇을 사랑하는 건 잘못된 게 아니야.","JPN":"ロボットを愛するのは間違ったことじゃないのよ。","ENG":"There's nothing wrong with being in love with a robot.","TWN":"愛上機器人並不是個錯。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"난 말이지. 사람처럼 생각하고 사람처럼 말한다면 무엇이든 사랑에 빠질 수 있다고 생각해.","JPN":"アタシはね、人のように考えて人のように話せるなら、\\n誰であれ恋に落ちることはあると思うの。","ENG":"I think people can fall in love with anything that can think and speak like a human.","TWN":"我個人認為，只要那個對象可以像人一般思考，像人一般說話，就可以和他談感情。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"하나 양이 진짜 사랑을 만나지 못하고 있는 건, 이미 그 로봇 사장님을 사람과 다름없는 존재라 믿고 있기 때문인 거야.","JPN":"スズカちゃんが本当の愛に巡り合えないのは、\\nすでにそのロボットの社長を人と変わらない存在だと信じているからなのよ。","ENG":"You haven't found someone because, in your mind, you're convinced that this robot boss is a man.","TWN":"你無法和其他人談戀愛的真正原因，是因為你相信，那個機器人老闆跟人沒有兩樣。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"안 그래?","JPN":"そうじゃない？","ENG":"Am I wrong?","TWN":"不是嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아…","JPN":"あ……","ENG":"Ah...","TWN":"喔…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"여, 역시 그런 걸까요?! 하하…","JPN":"や、やっぱりそうなんでしょうかね！　はは……","ENG":"Y-you think so? Hah hah...","TWN":"是…是這樣喔？！哈哈…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아아… 이제 알겠다… 전 로봇을 <color=#ffd34c>사람이라 생각하고</color> 좋아하고 있었던 거네요? 그렇죠?","JPN":"ああ……そういうことだったんですね……\\n私はロボットを<color=#ffd34c>人だと思って</color>好きになったんですね？　そうでしょう？","ENG":"Ah... I get it. So, I've unconsciously <color=#ffd34c>convinced myself that the robot is a man</color> and like him, right?","TWN":"喔喔…原來是這樣…我好像把機器人<color=#ffd34c>當人</color>，而且還喜歡他對吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그럼~ 기회가 된다면 그 사장님에게 하나 양의 진솔한 마음을 털어놔 봐.","JPN":"そうよ～。機会があれば、その社長にスズカちゃんの率直な気持ちを打ち明けてみてね。","ENG":"Yes. If you have a chance, you should tell him how you really feel about him.","TWN":"那有機會的話～就把你的心意老實地告訴老闆吧！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그리고 좋은 소식 있으면 나한테도 알려줘. 알았지?","JPN":"そして良い報告があればアタシにも教えてね。わかった？","ENG":"And let me know how it goes. Okay?","TWN":"有好消息的話，記得要告訴我喔！說定囉？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"영업 끝! 고생하셨습니다!","JPN":"営業終了！　お疲れ様でした！","ENG":"Wrap-up time! Good job, everyone!","TWN":"打烊！大家辛苦囉！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후우, 오늘 장사도 참 고됐네.","JPN":"ふぅ、今日の商売も大変だったわね。","ENG":"Whew, it was a tough day as usual.","TWN":"呼～今天也好累喔～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"역시 굉장하네요, 그레모리 씨!","JPN":"やっぱりすごいです、グレモリーさんは！","ENG":"You're incredible, Gremory!","TWN":"真不愧是葛茉莉，超強的！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"몇 마디 나누는 것만으로 하나 씨의 고민을 완벽하게 해결해 주셨잖아요!","JPN":"少し話しただけでスズカさんの悩みを完璧に解決してあげましたね！","ENG":"You perfectly solved Hana's problem just by talking to her for a while.","TWN":"不過幾句話就完美地解開荷娜的煩惱！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"내가 그랬나?","JPN":"そうだったっけ？","ENG":"Did I?","TWN":"我有嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그럼요! 상담에 얼마나 감명을 받았으면 밤새도록 칵테일을 아홉 잔이나 주문하셨겠어요?","JPN":"そうですよ！　相談内容に相当感動したのか、\\n一晩でカクテルを9杯も注文したんですよ？","ENG":"Absolutely! You made her so happy that she ordered nine cocktails in a row!","TWN":"有啊！要是沒效的話，她怎麼會整個晚上點了九杯雞尾酒？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하나 씨한테 말을 걸었던 손님들이 전부 어린아이처럼 울면서 도망가긴 했지만…","JPN":"スズカさんに声をかけたお客様たちは、\\nみんな子どものように泣きながら逃げていったけど……","ENG":"And she made all the customers who tried to talk to her run away crying...","TWN":"雖然向荷娜搭訕的客人，最後都哭得像孩子一樣奪門而出…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…그래도 인명사고는 없었으니까요!","JPN":"……でも怪我人はいなかったですし！","ENG":"Well, at least no one got hurt in the process!","TWN":"…不過至少沒有出人命啦！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후훗, 니콜 양의 지금 같은 긍정적인 마인드라면 나처럼 훌륭한 사랑 해결사가 되는 것도 그리 먼 이야기는 아니야.","JPN":"ふふっ、ニコルちゃんの今のようなポジティブマインドなら、\\nアタシのように立派な恋愛カウンセラーになるのもそんなに遠い話じゃないわね。","ENG":"Hah hah. Nicole, with your optimism, you can become a relationship expert like me in no time.","TWN":"呵呵～如果你一直都保持這種正面的心態，應該很快就能成為和我一樣優秀的愛情專家吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네! 열심히 하겠습니다!","JPN":"はい！　頑張ります！","ENG":"Okay, thanks!","TWN":"是！我會努力的！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"니콜……. 나 졸려…….","JPN":"ニコル……吾輩、眠くなってきた……","ENG":"Nicole... I'm sleepy...","TWN":"妮可……我想睡覺……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아, 잠시만 기다리세요. 가게 뒷정리만 마저 끝내고 책 읽어 줄게요.","JPN":"あ、少し待ってください。\\n店の後片付けだけ終わらせたら絵本を読んであげます。","ENG":"Oh, give me a moment. Let me finish cleaning the shop. I'll read you some books before bed.","TWN":"等等再睡，我還要整理一下店裡，整理完再說床邊故事給你聽。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"좋아!","JPN":"わかった！","ENG":"Okie!","TWN":"好！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그 전까지 양치하면서 기다리고 있어요.","JPN":"それまでに歯磨きして待っててくださいね。","ENG":"Now, go brush your teeth while waiting for me.","TWN":"那你先去刷牙等我。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"싫어!","JPN":"やだ！","ENG":"No!","TWN":"不要！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"싫다뇨! 양치 안 하면 충치 악마들이 와서 모모 이를 몽땅 뽑아갈 거라고요!","JPN":"いけません！　歯磨きをしないと虫歯の悪魔が来て、\\nモモの歯をぜーんぶ抜いていくんですよ！？","ENG":"No? If you don't brush, the bacteria devils will come to pull all your teeth out!","TWN":"什麼不要！不刷牙的話，蛀牙怪獸會來把你的牙齒拔光喔！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"추, 충치 악마들도 악마니까, 이 몸의 하수인이니라!","JPN":"む、虫歯の悪魔だって悪魔なんだから、吾輩の下僕である！","ENG":"B-bacteria devils are also devils, so they are my subjects, too!","TWN":"本…本王才不怕蛀牙怪獸！怪獸也是本王的手下！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하수인이라도 소용없어요. 악마는 원래 주인 말도 안 듣는 제멋대로인 존재라고요.","JPN":"下僕でもだめです。\\n悪魔はもともと主人の言うことも聞かないわがままな存在なんですよ？","ENG":"Doesn't matter. Devils don't listen to their masters, anyway.","TWN":"是你的手下又怎樣？蛀牙怪獸根本不聽主人的話！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"싫어어~!","JPN":"やだ～っ！","ENG":"Noooohhh!","TWN":"我不要啦～！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"임금님, 니콜 양 말 안 들으면 이 몽땅 뽑아버린다?","JPN":"王様、ニコルちゃんの言うことを聞かないとその歯、全部抜いちゃうよ？","ENG":"Your Majesty, you'd better listen to Nicole, or I'm going to pull all your teeth out.","TWN":"國王，你再不聽妮可的話，我要把你牙齒拔光囉？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"흐에엑!","JPN":"ほええっ！","ENG":"Heek!","TWN":"怕怕！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"치약… 주세요.","JPN":"歯磨き粉……ください。","ENG":"Toothpaste... please.","TWN":"給我…牙膏。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(정말 평화롭네요.)","JPN":"(本当に平和ですね。)","ENG":"(So peaceful.)","TWN":"(真是平靜～)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(일상이 매일 오늘만 같으면 좋겠어요.)","JPN":"(毎日が今日みたいだといいですね。)","ENG":"(I wish every day could be like today.)","TWN":"(真希望每天都像今天這樣。)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(하지만… 언제까지고 이렇게 지낼 수는 없는 거겠죠.)","JPN":"(ですが……いつまでもこの生活を続けるわけにはいかないでしょう。)","ENG":"(But... I can't stay like this forever.)","TWN":"(不過…這種生活不可能一直持續下去的吧？)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"아.","JPN":"あ。","ENG":"Ah.","TWN":"對了！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그러고 보니 니콜에게 줄 게 있었지.","JPN":"そういえばニコルちゃんに渡すものがあったわ。","ENG":"I almost forgot that I've got something for you, Nicole.","TWN":"我想起來有東西要給你。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저한테요?","JPN":"私にですか？","ENG":"For me?","TWN":"給我嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"자, 이거.","JPN":"さあ、これよ。","ENG":"Here, take this.","TWN":"這給你。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"조각케이크네요? 엄청 고급스럽다…….","JPN":"ケーキですね！　すごい高そうな……","ENG":"A slice of cake? It looks expensive.","TWN":"蛋糕？看起來好高級……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"와아! 케이크! 케이크!","JPN":"わーい！　ケーキ！　ケーキ！","ENG":"Whoa! Cake! Cake!","TWN":"哇～有蛋糕欸～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"지난번에 니콜에게 상담받았던 손님. 덕분에 애인이랑 잘 해결됐다나 봐.","JPN":"この前ニコルちゃんに相談していたお客さんがね、\\nおかげで恋人とうまく解決したって。","ENG":"The customer you talked to last time. She made up with her boyfriend.","TWN":"是上次妮可接待的客人送的，好像跟你聊完後感情又死灰復燃。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그래서 이렇게 답례라며 선물을 보내왔어.","JPN":"それで、お礼がしたいとこれを贈ってくれたの。","ENG":"She sent it to you as a thank-you gift.","TWN":"所以就寄這個過來，說是要給你的謝禮。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"제 상담의… 답례…","JPN":"私が乗った相談の……お礼……","ENG":"A thank-you gift...","TWN":"給我的…謝禮…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(그렇군요.)","JPN":"(そうでした。)","ENG":"(I see.)","TWN":"(原來如此。)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(비록 성서의 말씀을 빌린 고해성사의 자리는 아니었지만…)","JPN":"(聖書の言葉を引用したゆるしの秘跡ではなかったのですが……)","ENG":"(Even though I wasn't in the confessional...)","TWN":"(雖然我沒有引經據典…)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(만화에서 배운 지식을 빌려 바에서 손님들과 대화를 나누는 것만으로 사람들의 고민을 해결해 줄 수 있는 거네요.)","JPN":"(漫画で学んだ知識を活かして、バーでお客様と会話をするだけで\\n人々の悩みを解決できるのですね。)","ENG":"(I tried to listen to her as best as I could, using the knowledge from the comics I read, and it really helped her.)","TWN":"(而是用漫畫裡學到的知識來和客人交談，原來這樣也可以解決人的煩惱。)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(저란 사람은… 언제나 보이는 겉모습에만 너무 연연하고 있었던 걸지도 몰라요.)","JPN":"(私という人間は……\\nいつも目に見える外見ばかりに執着しすぎていたのかもしれません。)","ENG":"(Maybe, I wonder if I was obsessed with appearances instead of what's underneath...)","TWN":"(我之前…或許都太執著於表面看到的東西。)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"헤헤……","JPN":"えへへっ……","ENG":"Heh heh...","TWN":"嘿嘿……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"니콜~ 이 몸도 케이크가 먹고 싶도다.","JPN":"ニコル～吾輩もケーキが食べたいのだ。","ENG":"Nicole, I want to eat your cake, too.","TWN":"妮可～本王也想吃蛋糕～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네, 같이 먹어요.","JPN":"はい、一緒に食べましょう。","ENG":"Sure, you can have some.","TWN":"好啊，大家一起吃吧～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"대신 먹고 나서 양치 꼭 하는 거예요?","JPN":"代わりに、食べた後は必ず歯磨きですよ？","ENG":"But you'll brush your teeth afterward. Promise?","TWN":"不過你吃完一定要刷牙喔？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"응! 물론이니라!","JPN":"うむ！　もちろんだぞ！","ENG":"Okie! I promise!","TWN":"好！一定要的！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"이 시간이 영원하길 바라진 않아요.","JPN":"この時間が永遠に続くことを願ってはいません。","ENG":"I don't expect this to last forever.","TWN":"我不奢望時間就可以就此暫停。"},"stage":{"bg":"BLACK","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"후회가 없기를 바라는 것도 욕심이겠죠.","JPN":"後悔がないことを願うのも私の欲でしょう。","ENG":"I'd be greedy if I wanted no regrets, too.","TWN":"期待沒有後悔也是種奢求。"},"stage":{"bg":"BLACK","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"narration","speaker":null,"text":{"KOREA":"다만, 저에게 주어진 이 모든 시간에 그만한 가치가 있기를…","JPN":"ただ、私に与えられたこのすべての時間に、\\nそれだけの価値がありますように……","ENG":"But I will pray to myself...","TWN":"我只希望在我有限的時間內，可以活得有價值…"},"stage":{"bg":"BLACK","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"이번엔 저 자신에게 기도하겠어요.","JPN":"今度は自分自身に祈ります。","ENG":"that all the time given to me will be valuable.","TWN":"這是我對我自己的祈禱。"},"stage":{"bg":"BLACK","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};